  ('customs-7fec267e-moex-00256', 'customs-7fec267e', 'customs-7fec267e-moex-111-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '如果兩個要素投入是毛互補，那麼兩個要素投入的需求交叉工資彈性將是：', '["0", "1", "正的", "負的"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:22+00:00", "source_pdf_sha1": "9e4c296907e5", "answer_pdf_sha1": "4f3eb1fbbf91", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "141", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00257', 'customs-7fec267e', 'customs-7fec267e-moex-111-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '市場的需求函數為Q=10–P，其中Q為數量，P為價格。市場上僅有兩家廠商，其成本函數皆 為TC = 2Q，其中TC為總成本。如果這兩家廠商決定採取聯合定價來極大化聯合利潤，一起壟 斷市場。此時的市場價格為何？', '["$2", "$4", "$6", "$8"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:22+00:00", "source_pdf_sha1": "9e4c296907e5", "answer_pdf_sha1": "4f3eb1fbbf91", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "141", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00258', 'customs-7fec267e', 'customs-7fec267e-moex-111-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '假設市場供給曲線是正斜率，需求曲線是負斜率。當政府對完全競爭市場課徵從量稅時，下列有關長 期均衡的敘述，何者正確？', '["價格會上升，數量會上升", "價格會下降，數量會上升", "價格會上升，數量會下降", "價格會下降，數量會下降"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:22+00:00", "source_pdf_sha1": "9e4c296907e5", "answer_pdf_sha1": "4f3eb1fbbf91", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "141", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00259', 'customs-7fec267e', 'customs-7fec267e-moex-111-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '當獨占廠商選擇使用完全差別取價訂價法（或是所謂的第一級差別取價訂價法）時，消費者所面對的 交易價格為：', '["該獨占廠商的平均成本", "該獨占廠商的邊際成本", "該消費者對此商品的願付價格", "全部消費者對此商品的平均願付價格"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:22+00:00", "source_pdf_sha1": "9e4c296907e5", "answer_pdf_sha1": "4f3eb1fbbf91", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "141", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00260', 'customs-7fec267e', 'customs-7fec267e-moex-111-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '小新擁有一間處於完全競爭市場的小花店，她正在考慮是否要多僱用一名員工，員工的工資是每週 $500，多僱用一名員工的邊際產量是每週100個單位，且每單位產品價格是$10。小新應該要怎麼做？', '["多僱用一名員工", "不要再多僱用這名員工", "提高她所販售花的定價", "沒有足夠的資訊來回答這個問題"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:22+00:00", "source_pdf_sha1": "9e4c296907e5", "answer_pdf_sha1": "4f3eb1fbbf91", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "141", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00261', 'customs-7fec267e', 'customs-7fec267e-moex-111-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '假如多僱用一個單位勞動所造成的產出增加量，使得_____的增加大於_____的增加，那麼這個廠商 會因為增加這個勞動的僱用而提高利潤。', '["總成本；總收入", "平均收入；平均成本", "邊際成本；邊際收入", "邊際收入；邊際成本"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:22+00:00", "source_pdf_sha1": "9e4c296907e5", "answer_pdf_sha1": "4f3eb1fbbf91", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "141", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00262', 'customs-7fec267e', 'customs-7fec267e-moex-111-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '下列何種情況會發生公地悲劇（tragedyofthecommons）？', '["在私有草地養羊", "在近海採集海膽", "釣蝦場裏養蝦", "使用圖書館裏的借書服務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:22+00:00", "source_pdf_sha1": "9e4c296907e5", "answer_pdf_sha1": "4f3eb1fbbf91", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "141", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00263', 'customs-7fec267e', 'customs-7fec267e-moex-111-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '「坐享其成」對於私人興建的遊樂園不是嚴重的問題，因為：', '["遊樂園是具有敵對性的商品", "遊樂園園方有權禁止不付費的遊客使用遊樂設施", "遊樂園不具有外部性", "私人興建的遊樂園本來就存在坐享其成的問題"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:22+00:00", "source_pdf_sha1": "9e4c296907e5", "answer_pdf_sha1": "4f3eb1fbbf91", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "141", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00264', 'customs-7fec267e', 'customs-7fec267e-moex-111-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '下列關於「契約曲線」（contractcurve）之敘述，何者正確？', '["線上各點均滿足柏瑞圖效率（Paretoefficiency）", "線上各點均可使社會福利極大", "線上各點均可使資源平均分配", "線上各點必然是競爭市場均衡"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:22+00:00", "source_pdf_sha1": "9e4c296907e5", "answer_pdf_sha1": "4f3eb1fbbf91", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "141", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00265', 'customs-7fec267e', 'customs-7fec267e-moex-111-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '社會中只有兩位同質的消費者，而個別消費者由公共財所獲得之邊際利益為MB=20–G，此處G為 公共財之數量。若提供每單位公共財之成本為10，下列何者為社會最適之公共財數量？', '["10", "15", "20", "25"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:22+00:00", "source_pdf_sha1": "9e4c296907e5", "answer_pdf_sha1": "4f3eb1fbbf91", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "141", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL)
